#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 printf("Before fork - PID: %d\n", getpid());

 pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 printf("Child: My PID = %d, Parent PID = %d\n", 
 getpid(), getppid());
 printf("Child: fork() returned 0 to me\n");
 }
 else {
 // Parent process
 printf("Parent: My PID = %d, Child PID = %d\n", 
 getpid(), pid);
 printf("Parent: fork() returned child's PID to me\n");

 // Wait for child to complete
 wait(NULL);
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid == 0) {
 // Child process
 printf("Child (PID %d): Exiting now...\n", getpid());
 exit(0); // Child terminates, becomes zombie
 }
 else if (pid > 0) {
 // Parent process
 printf("Parent (PID %d): Created child with PID %d\n", 
 getpid(), pid);
 printf("Parent: Sleeping without calling wait()...\n");
 sleep(10); // Parent sleeps without calling wait()
 // Child becomes zombie during this time

 // After sleep, call wait to clean up zombie
 wait(NULL);
 printf("Parent: Called wait(), zombie cleaned up\n");
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid == 0) {
 // Child process
 printf("Child (PID %d): Starting, parent is %d\n", 
 getpid(), getppid());

 sleep(2); // Wait for parent to terminate

 printf("Child (PID %d): After sleep, parent is now %d\n", 
 getpid(), getppid());
 // Now parent should be init (PID 1)
 }
 else if (pid > 0) {
 // Parent process
 printf("Parent (PID %d): Created child %d, will exit soon\n", 
 getpid(), pid);
 sleep(1); // Sleep briefly then exit
 printf("Parent: Exiting now, child will become orphan\n");
 exit(0); // Parent terminates before child
 }

 return 0;
}
